class Solution {
public:
    string crackSafe(int n, int k) {
        string res = string(n, '0');
        int total = pow(k, n);
        unordered_set<string> visited;
        visited.insert(res);
        dfs(res, total, visited, n, k);
        return res;
    }

    bool dfs(string& res, int total, unordered_set<string>& visited, int n, int k) {
        if (visited.size() == total) return true;
        string last = res.substr(res.size() - n + 1);
        for (int i = 0; i < k; ++i) {
            string next = last + to_string(i);
            if (!visited.count(next)) {
                visited.insert(next);
                res += to_string(i);
                if (dfs(res, total, visited, n, k)) return true;
                res.pop_back();
                visited.erase(next);
            }
        }
        return false;
    }
};
